/**
 * @name Path traversal from HTTP request to filesystem in WildFly
 * @description Taint flow from HTTP request parameters/path to File/filesystem operations without proper sanitization
 * @kind path-problem
 * @problem.severity error
 * @id java/wildfly-http-path-traversal
 * @tags security
 *       external/cwe/cwe-022
 */
import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module PathTraversalConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // HTTP request sources
    exists(MethodCall mc |
      (
        mc.getMethod().hasName("getPathInfo") or
        mc.getMethod().hasName("getServletPath") or
        mc.getMethod().hasName("getRequestURI") or
        mc.getMethod().hasName("getRequestURL") or
        mc.getMethod().hasName("getParameter") or
        mc.getMethod().hasName("getHeader")
      ) and
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // File constructor sinks
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "File") and
      sink.asExpr() = ce.getAnArgument()
    )
    or
    // FileInputStream
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "FileInputStream") and
      sink.asExpr() = ce.getAnArgument()
    )
    or
    // Paths.get
    exists(MethodCall mc |
      mc.getMethod().hasName("get") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.nio.file", "Paths") and
      sink.asExpr() = mc.getAnArgument()
    )
  }
}

module PathTraversalFlow = TaintTracking::Global<PathTraversalConfig>;
import PathTraversalFlow::PathGraph

from PathTraversalFlow::PathNode source, PathTraversalFlow::PathNode sink
where PathTraversalFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Path traversal: HTTP request data flows to filesystem operation from $@.", source.getNode(), "HTTP source"

/**
 * @name ZipEntry path traversal (zip slip)
 * @description ZipEntry.getName() flowing to file path construction without traversal check
 * @kind problem
 * @problem.severity error
 * @id java/zip-slip-check
 * @tags security
 *       external/cwe/cwe-022
 */
import java
import semmle.code.java.dataflow.TaintTracking

module ZipSlipConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    exists(MethodCall mc |
      mc.getMethod().hasName("getName") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.util.zip", "ZipEntry") and
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "File") and
      sink.asExpr() = ce.getArgument(0)
    )
    or
    exists(MethodCall mc |
      mc.getMethod().hasName("get") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.nio.file", "Paths") and
      sink.asExpr() = mc.getAnArgument()
    )
  }
}

module ZipSlipFlow = TaintTracking::Global<ZipSlipConfig>;

from DataFlow::Node source, DataFlow::Node sink
where ZipSlipFlow::flow(source, sink)
select sink, "ZipEntry name flows to file path construction - potential zip slip vulnerability"
